      "komfort-k7": { name: "Комфорт К-7", short: "Изящный минимализм со стеклянным акцентом", description: "Истинный манифест сдержанности для тех, кто видит красоту в отсутствии лишних деталей. Дизайн с декоративным стеклянным элементом создаёт по-настоящему премиальное помещение." },
      "modern-m1-black": { name: "Модерн М-1 Чёрный", short: "Современный стиль с хай-тек текстурой Муар", description: "Современный стиль и инженерное превосходство. Чёрная отделка с фирменным горизонтальным рисунком текстуры «Муар» превращает входную группу в элемент современной архитектуры." },
