      "modern-m3-beton": { name: "Модерн М-3 Бетон", short: "Бетонная фактура с чистотой формы", description: "Давит ставку на чистоту формы и сдержанность. Вертикальное обрамление по всей высоте полотна создаёт конструкцию монументальную и одновременно манящую." },
      "modern-m3-chestnut": { name: "Модерн М-3 Каштан тёмный", short: "Тёмный каштан с глубокой натуральной текстурой", description: "Воплощение урбанистической стильности, созданное для современных интерьеров в дома и квартиры. Глубина натурального каштана с вертикальными деталями создаёт монументальный силуэт." },
      "modern-m4-carbon": { name: "Модерн М-4 Карбон", short: "Карбоновый арт — сплав индустрии и утончённости", description: "Представляет собой арт-форму, где игра пропорций и материалов создаёт компактный геометрический паттерн с активными материальными акцентами." },
